class Solution {
public:
	int maxNonStapled(vector<int>& pages) {
		if (pages.size() < 2) return pages.size();
		int ans = pages[0];
		for (int i = 1; i < pages.size() && i < 3; i++) {
			ans += pages[i] - pages[i - 1];
		}
		return ans;
	}
};

solutions.python:
class Solution:
	def maxNonStapled(self, pages: list[int]) -> int:
		if len(pages) < 2: return len(pages)
		ans = pages[0]
		for i in range(1, min(len(pages), 3)):
			ans += pages[i] - pages[i - 1]
		return ans
